import heapq

def simulate(events0, handlers, end_time):
    # events0: list[(time, event_type, payload)]
    # handlers: dict[event_type, callable(state, time, payload) -> list[(time, event_type, payload)]]
    q = list(events0)
    heapq.heapify(q)
    state = {}
    trace = []
    while q:
        t, et, payload = heapq.heappop(q)
        if t > end_time:
            break
        trace.append((t, et, payload))
        for new_ev in handlers[et](state, t, payload):
            heapq.heappush(q, new_ev)
    return state, trace
